module RefModule (
    input wire clk,
    input wire rst,
    input wire load,
    input wire [15:0] parallel_in,
    output wire serial_out
);

    reg [15:0] unused_shift_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            unused_shift_reg <= 16'b0;
        end else if (load) begin
            unused_shift_reg <= parallel_in;
        end else begin
            unused_shift_reg <= {unused_shift_reg[14:0], 1'b0};
        end
    end

    assign serial_out = unused_shift_reg[15];

endmodule
